const source = (items[0] && items[0].json) ? items[0].json : {};
const docs = Array.isArray(source.result) ? source.result : [];

return docs
  .filter((doc) => doc && typeof doc === 'object')
  .map((doc) => ({ json: doc }));

const bodyBlocks = Array.isArray($json.body) ? $json.body : [];
const bodyText = bodyBlocks
  .flatMap((block) => (Array.isArray(block.children) ? block.children : []))
  .map((child) => child.text || '')
  .join(' ');

const wordCount = bodyText.split(/\s+/).filter(Boolean).length;
let score = 100;
const flags = [];

if (wordCount < 700) {
  score -= 25;
  flags.push('body_too_short');
}
if (wordCount > 1800) {
  score -= 10;
  flags.push('body_too_long');
}

const seoTitle = String($json.seoTitle || '');
const seoDescription = String($json.seoDescription || '');

if (seoTitle.length < 35 || seoTitle.length > 70) {
  score -= 8;
  flags.push('seo_title_length');
}
if (seoDescription.length < 90 || seoDescription.length > 170) {
  score -= 8;
  flags.push('seo_description_length');
}

if (!$json.coverImage || !$json.coverImageAlt) {
  score -= 20;
  flags.push('image_missing');
}

const riskyPatterns = [/guarantee/i, /cure/i, /instant results/i, /structural repair/i, /licensed electrician/i];
if (riskyPatterns.some((p) => p.test(String($json.title || '') + ' ' + String($json.excerpt || '') + ' ' + bodyText))) {
  score -= 30;
  flags.push('risky_claim_language');
}

const finalScore = Math.max(0, score);
const readTimeMinutes = Math.max(1, Math.round(wordCount / 220));

return {
  json: {
      ...$json,
      qaScore: finalScore,
      qaFlags: flags,
      qaChecks: {
        wordCount,
        seoComplete: Boolean(seoTitle && seoDescription),
        duplicateScore: 0,
        readability: 0,
      },
      readTimeMinutes,
    },
};

