const nf = (typeof fetch === 'function') ? null : require('node-fetch');
const fetchFn = (typeof fetch === 'function') ? fetch : (nf.default || nf);

const source = $('Compute QA Score').item.json;
const qaScore = Number(source.qaScore || 0);
const qaFlags = Array.isArray(source.qaFlags) ? source.qaFlags : [];
const qaChecks = source.qaChecks || {};
const pipelineMode = source.pipelineMode || (source.aiMeta && source.aiMeta.pipelineMode) || 'prepopulate_bulk_direct';
const decision = qaScore < 75 ? 'reject' : 'publish';
const siteSlug = String(source.siteSlug || $env.SITE_SLUG || '').toLowerCase().trim();
if (!siteSlug) throw new Error('Missing siteSlug in QA log writer');

const apiVersion = $('Resolve Site Context').item.json.sanity.apiVersion || '2025-01-01';
const projectId = $('Resolve Site Context').item.json.sanity.projectId;
const dataset = $('Resolve Site Context').item.json.sanity.dataset || 'production';
const writeToken = $('Resolve Site Context').item.json.sanity.writeToken;

if (!projectId || !writeToken) {
  throw new Error('Missing Sanity env vars for qaLog');
}

const mutateUrl = 'https://' + projectId + '.api.sanity.io/v' + apiVersion + '/data/mutate/' + dataset;
const body = {
  mutations: [
    {
      create: {
        _type: 'qaLog',
        siteSlug,
        article: source._id ? { _type: 'reference', _ref: source._id } : undefined,
        workflowRunId: String($execution.id),
        score: qaScore,
        decision,
        flags: qaFlags.concat(pipelineMode === 'steady_scheduled' && qaScore >= 75 ? ['queued_for_scheduler'] : []),
        checks: {
          wordCount: qaChecks.wordCount || 0,
          seoComplete: Boolean(qaChecks.seoComplete),
          duplicateScore: Number(qaChecks.duplicateScore || 0),
          readability: Number(qaChecks.readability || 0),
        },
        createdAt: new Date().toISOString(),
      },
    },
  ],
};

const res = await fetchFn(mutateUrl, {
  method: 'POST',
  headers: {
    Authorization: 'Bearer ' + writeToken,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify(body),
});

if (!res.ok) {
  const text = await res.text();
  throw new Error('qaLog create failed (' + res.status + '): ' + text);
}

const json = await res.json();
return { json: { ...$json, qaLogDecision: decision, qaLogScore: qaScore, qaLogResult: json } };

